from collections import deque

class Solution(object):
    def minSplitMerge(self, nums1, nums2):
        start = tuple(nums1)
        target = tuple(nums2)
        if start == target:
            return 0

        visited = {start}
        queue = deque([(start, 0)])

        while queue:
            state, steps = queue.popleft()
            n = len(state)
            for l in range(n):
                for r in range(l, n):
                    sub = state[l:r + 1]
                    rest = state[:l] + state[r + 1:]
                    for pos in range(len(rest) + 1):
                        new_state = rest[:pos] + sub + rest[pos:]
                        if new_state == target:
                            return steps + 1
                        if new_state not in visited:
                            visited.add(new_state)
                            queue.append((new_state, steps + 1))

        return -1
